#include <stdio.h>
#include <string.h>

int main() {
    char tekst[100] = "Ovo je 1 primjer";
    char *s = tekst;
    char jedan[] = "jedan";
    int duzina = strlen(jedan), i;

    while (*s != '\0') {
        if (*s == '1') {
            char *kraj = s;
            while (*kraj != '\0') kraj++;
            while (kraj >= s) {
                *(kraj + duzina - 1) = *kraj;
                kraj--;
            }
            for (i = 0; i < duzina; i++) {
                *(s + i) = jedan[i];
            }

            s += duzina;
        } else {
            s++;
        }
    }

    printf("%s\n", tekst);
    return 0;
}
